class Solution:
    def leastOpsExpressTarget(self, x: int, target: int) -> int:
        dp = [float('inf')] * (target + 1)
        dp[0] = 0
        for i in range(1, target + 1):
            for op in ['+', '-', '*', '/']:
                if op == '+':
                    if i - x >= 0:
                        dp[i] = min(dp[i], dp[i - x] + 1)
                elif op == '-':
                    if i + x <= target:
                        dp[i] = min(dp[i], dp[i + x] + 1)
                elif op == '*':
                    if i // x >= 0:
                        dp[i] = min(dp[i], dp[i // x] + 1)
                elif op == '/':
                    if i * x <= target:
                        dp[i] = min(dp[i], dp[i * x] + 1)
        return dp[target]
